const createId = (prefix = 'item') => (
	`${prefix}-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`
);

export const createAnnualReport = (overrides = {}) => ({
	id: createId('annual'),
	ext: 'PDF',
	title: 'Новый годовой документ',
	meta: '',
	url: '',
	opensInNewTab: true,
	...overrides,
});

export const normalizeAnnualReport = (item = {}, index = 0) => ({
	id: item.id || `annual-${index}`,
	ext: item.ext || 'PDF',
	title: item.title || '',
	meta: item.meta || '',
	url: item.url || '',
	opensInNewTab: !!item.opensInNewTab,
});

export const normalizeAnnualReports = (items, fallback = DEFAULT_ANNUAL_REPORTS) => {
	const source = Array.isArray(items) && items.length ? items : fallback;
	return source.map(normalizeAnnualReport);
};

export const createInterimDocument = (overrides = {}) => ({
	id: createId('interim-doc'),
	title: 'Новый документ',
	meta: '',
	url: '',
	opensInNewTab: true,
	...overrides,
});

export const normalizeInterimDocument = (item = {}, index = 0) => ({
	id: item.id || `interim-doc-${index}`,
	title: item.title || '',
	meta: item.meta || '',
	url: item.url || '',
	opensInNewTab: !!item.opensInNewTab,
});

export const createInterimGroup = (overrides = {}) => ({
	id: createId('interim-group'),
	title: 'Новая группа промежуточной отчетности',
	open: false,
	documents: [createInterimDocument()],
	...overrides,
});

export const normalizeInterimGroup = (group = {}, index = 0) => ({
	id: group.id || `interim-group-${index}`,
	title: group.title || '',
	open: !!group.open,
	documents: Array.isArray(group.documents)
		? group.documents.map(normalizeInterimDocument)
		: [],
});

export const normalizeInterimGroups = (groups, fallback = DEFAULT_INTERIM_GROUPS) => {
	const source = Array.isArray(groups) && groups.length ? groups : fallback;
	return source.map(normalizeInterimGroup);
};

